B.TB=new A.L("Introdu\xe7\xe3o","O PerfectGest I oferece controlo claro dos dados, em conformidade com a Google Play e a LGPD. A app \xe9 local-first.")
B.RF=new A.L("Resumo","Dados de clientes e financeiros n\xe3o s\xe3o enviados automaticamente para servidores PerfectGest. S\xf3 podem sair do telem\xf3vel se partilhar PDFs, partilhar ficheiros de backup que exportou, partilhar PNG/vCard do cart\xe3o de visita ou mostrar um QR com contactos profissionais.")
B.Uy=new A.L("1. Dados de gest\xe3o (local)","Armazenados em SQLite no dispositivo: clientes, or\xe7amentos, caixa, ordens de servi\xe7o, dados da empresa, c\xf3pia do cart\xe3o de visita, lembretes fiscais.\n\nComo eliminar\n\n- Na app: Configura\xe7\xf5es \u2192 Dados no dispositivo \u2192 Eliminar todos os dados neste aparelho\n- Android: Defini\xe7\xf5es \u2192 Apps \u2192 PerfectGest I \u2192 Armazenamento \u2192 Limpar dados\n- Desinstalar a app\n\nAviso: sem c\xf3pia externa, n\xe3o h\xe1 recupera\xe7\xe3o \u2014 n\xe3o guardamos c\xf3pias nos nossos servidores.\n\nBackups partilhados: elimine manualmente no WhatsApp, e-mail ou nuvem onde os guardou.")
B.RR=new A.L("2. Firebase / telemetria","Metadados an\xf3nimos de instala\xe7\xe3o e m\xe9tricas de uso para elegibilidade do Plano Inicial. N\xe3o alojamos conte\xfado do cart\xe3o de visita em servidores.\n\nE-mail: suporte@perfectgestdev.com \u2014 Assunto: Solicita\xe7\xe3o de Exclus\xe3o de Dados T\xe9cnicos")
B.SB=new A.L("3. Notifica\xe7\xf5es locais","Canceladas ao desinstalar ou ao apagar os dados na app.")
B.Tf=new A.L("4. Prazos","Dados locais: imediato. Telemetria Firebase: at\xe9 15 dias \xfateis ap\xf3s pedido por e-mail.")
B.YH=s([B.TB,B.RF,B.Uy,B.RR,B.SB,B.Tf],t.h)
B.jp=s(["\u0627\u062a\u0648\u0627\u0631","\u067e\u06cc\u0631","\u0645\u0646\u06af\u0644","\u0628\u062f\u06be","\u062c\u0645\u0639\u0631\u0627\u062a","\u062c\u0645\u0639\u06c1","\u06c1\u0641\u062a\u06c1"],t.s)
B.RQ=new A.L("O que \xe9 o PerfectGest I?","Aplica\xe7\xe3o de gest\xe3o no telem\xf3vel, com dados guardados localmente (SQLite). N\xe3o h\xe1 \xabconta na nuvem\xbb PerfectGest para clientes, or\xe7amentos ou caixa.")
B.SD=new A.L("A app funciona sem internet?","Sim, o uso di\xe1rio \xe9 offline-first. Servi\xe7os Google opcionais (Analytics, Remote Config, Firestore m\xednimo para o Plano Inicial) podem usar rede quando activos.")
B.Tr=new A.L("Como funciona o per\xedodo de teste?","7 dias desde a primeira abertura. Durante esse tempo: at\xe9 5 clientes, 5 or\xe7amentos e 5 lan\xe7amentos de caixa (com PDF), sem subscri\xe7\xe3o paga. Ao guardar o 4.\xba de cada tipo, a app avisa que falta 1. O 6.\xba ou o fim dos 7 dias sem Plano Pro impede novos registos; pode continuar a consultar e editar o que j\xe1 est\xe1 no telem\xf3vel. Subscri\xe7\xe3o: Configura\xe7\xf5es \u2192 Assinatura Google Play.")
B.Tt=new A.L("Como funciona o Plano Inicial?","\xc9 o conjunto de limites 5+5+5 aplicado durante os 7 dias de teste (ver acima). Fora do teste ou acima dos limites, \xe9 necess\xe1rio o Plano Pro (mensal ou anual na Google Play).")
B.Ug=new A.L("Onde compro ou gerencio a subscri\xe7\xe3o?","Configura\xe7\xf5es \u2192 Assinatura Google Play. Pagamentos pelo Google. Cancelamento: Play Store \u2192 Pagamentos e subscri\xe7\xf5es \u2192 Subscri\xe7\xf5es.")
B.RW=new A.L("O que \xe9 o cart\xe3o de visita digital?","Na aba Empresa edita os dados profissionais da empresa (n\xe3o inclui clientes nem caixa). O cart\xe3o mostra log\xf3tipo, nome, slogan, CNPJ, nome do profissional e contactos com r\xf3tulos no rodap\xe9 (at\xe9 2 por linha). Temas: branco, cinza ou preto.\n\nPartilhar cart\xe3o de visita gera PNG e abre a folha de partilha (WhatsApp, e-mail, etc.). Ap\xf3s o primeiro cart\xe3o, sem Plano Pro o cart\xe3o fica em modo est\xe1tico (pode partilhar o PNG do snapshot); com Pro, edita e usa fun\xe7\xf5es avan\xe7adas s\xf3 na app (vCard, QR, preview interactivo) \u2014 sem p\xe1gina web alojada pela PerfectGest.\n\nClientes e dados financeiros ficam protegidos: s\xf3 no telem\xf3vel; n\xe3o entram no cart\xe3o nem s\xe3o enviados automaticamente para servidores.")
B.Sd=new A.L("Os meus dados de clientes e financeiros est\xe3o protegidos?","Sim. Clientes, or\xe7amentos, caixa e valores ficam na base local. A app n\xe3o envia esses dados para servidores.\n\nS\xf3 saem do telem\xf3vel se voc\xea decidir:\n\n- Partilhar um PDF\n- Partilhar o cart\xe3o de visita (PNG, vCard ou QR \u2014 contactos profissionais)\n- Partilhar um backup exportado em Configura\xe7\xf5es (recomendamos backup encriptado no Plano Pro)")
B.Se=new A.L("O que s\xe3o os lembretes fiscais?","Obriga\xe7\xf5es pr\xe9-configuradas (MEI, Aut\xf4nomo, ME) com alarmes no dispositivo. Meramente informativos \u2014 n\xe3o substituem contabilista.")
B.S0=new A.L("O que \xe9 o calend\xe1rio semanal?","Na aba Empresa, calend\xe1rio da semana com indicadores de vencimentos fiscais.")
B.SY=new A.L("O que s\xe3o os \xab\xdaltimos lan\xe7amentos\xbb?","Atalhos na p\xe1gina inicial para o \xfaltimo cliente, or\xe7amento, ordem de servi\xe7o e lan\xe7amento de caixa.")
B.Sf=new A.L("A app envia notifica\xe7\xf5es?","Apenas notifica\xe7\xf5es locais para lembretes fiscais. Sem envio a servidores externos.")
B.TU=new A.L("Onde est\xe1 a pol\xedtica de privacidade?","Configura\xe7\xf5es \u2192 Ajuda e suporte \u2014 links para Pol\xedtica, Exclus\xe3o de dados e Termos. E-mail: suporte@perfectgestdev.com.")
B.U2=new A.L("Como apago todos os dados neste aparelho?","Configura\xe7\xf5es \u2192 Dados no dispositivo \u2192 Eliminar todos os dados neste aparelho. N\xe3o apaga PDFs ou backups j\xe1 exportados. Para dados t\xe9cnicos Google: p\xe1gina de exclus\xe3o de dados.")
B.SH=new A.L("A app tem an\xfancios?","N\xe3o.")
B.Uc=new A.L("H\xe1 Firebase Crashlytics?","N\xe3o. Analytics regista eventos gen\xe9ricos; n\xe3o envia crash reports autom\xe1ticos.")
B.Sm=new A.L("Em que idiomas est\xe1 a app?","Portugu\xeas (Brasil), ingl\xeas (EUA), espanhol (Espanha).")
B.Us=new A.L("Como posso dar sugest\xf5es?","Aba Empresa \u2192 D\xea sua contribui\xe7\xe3o \u2192 e-mail suporte@perfectgestdev.com.")
B.YI=s([B.RQ,B.SD,B.Tr,B.Tt,B.Ug,B.RW,B.Sd,B.Se,B.S0,B.SY,B.Sf,B.TU,B.U2,B.SH,B.Uc,B.Sm,B.Us],t.h)
