B.Uf=new A.L("1. Aceita\xe7\xe3o","Ao instalar ou utilizar o PerfectGest-Clinica III, o utilizador concorda com estes Termos.")
B.Ub=new A.L("2. Escopo","O app \xe9 uma ferramenta de apoio \xe0 gest\xe3o cl\xednica e organizacional. N\xe3o substitui, em hip\xf3tese alguma, julgamento profissional, diagn\xf3stico ou tratamento m\xe9dico.")
B.Sv=new A.L("3. Contas e responsabilidades","\u2022 O utilizador \xe9 respons\xe1vel por manter as credenciais (utilizador e senha) em seguran\xe7a.\n\u2022 A cl\xednica ou profissional que utiliza o software \xe9 respons\xe1vel pelo conte\xfado inserido e pelo uso adequado do sistema.")
B.RH=new A.L("4. Uso aceit\xe1vel","\xc9 proibido:\n\u2022 usar o app para fins ilegais;\n\u2022 tentar contornar mecanismos de seguran\xe7a;\n\u2022 introduzir c\xf3digo malicioso;\n\u2022 copiar, distribuir ou explorar comercialmente o software fora dos limites da licen\xe7a.")
B.T9=new A.L("5. Dados e backups","\u2022 Os dados cl\xednicos s\xe3o armazenados localmente no dispositivo.\n\u2022 Backups exportados manualmente devem ser guardados com seguran\xe7a pela cl\xednica.")
B.TL=new A.L("6. Compras na aplica\xe7\xe3o (Microsoft Store)","Subscri\xe7\xf5es, quando aplic\xe1vel, s\xe3o processadas pela Microsoft Store (Microsoft Corporation). Pagamentos e gest\xe3o de subscri\xe7\xe3o s\xe3o feitos pela conta Microsoft do utilizador. A Perfect Gest Dev n\xe3o processa nem armazena dados de cart\xe3o.")
B.SJ=new A.L("7. Limita\xe7\xe3o de responsabilidade","Empregamos esfor\xe7os para manter o app funcional e seguro, mas n\xe3o garantimos opera\xe7\xe3o ininterrupta. O uso do app e as decis\xf5es cl\xednicas tomadas com base nos dados inseridos s\xe3o de responsabilidade da cl\xednica ou do profissional de sa\xfade.")
B.TA=new A.L("8. Encerramento","Podemos suspender o acesso em caso de viola\xe7\xe3o destes Termos ou por exig\xeancia legal.")
B.T_=new A.L("9. Altera\xe7\xf5es","Podemos actualizar estes Termos. A continua\xe7\xe3o do uso ap\xf3s altera\xe7\xf5es significativas significa aceita\xe7\xe3o da vers\xe3o actualizada.")
B.Uw=new A.L("10. Contato","suporte@perfectgestdev.com")
B.a_o=s([B.Uf,B.Ub,B.Sv,B.RH,B.T9,B.TL,B.SJ,B.TA,B.T_,B.Uw],t.h)
